alter table public.profiles add column onboarding_completed_at timestamptz;
alter table public.profiles add column weekly_goal text check (weekly_goal in ('understand','save','debt','bills'));
create unique index categories_workspace_kind_name_key on public.categories(workspace_id,kind,lower(name));
create or replace function public.bootstrap_personal_workspace(p_display_name text,p_workspace_name text default 'Minhas finanças',p_weekly_goal text default 'understand') returns uuid language plpgsql security invoker set search_path='' as $$ declare v_user_id uuid:=(select auth.uid());v_workspace_id uuid;begin if v_user_id is null then raise exception 'authentication required';end if;if p_weekly_goal not in ('understand','save','debt','bills') then raise exception 'invalid goal';end if;insert into public.profiles(id,display_name,weekly_goal,onboarding_completed_at) values(v_user_id,nullif(trim(p_display_name),''),p_weekly_goal,now()) on conflict(id) do update set display_name=excluded.display_name,weekly_goal=excluded.weekly_goal,onboarding_completed_at=coalesce(public.profiles.onboarding_completed_at,excluded.onboarding_completed_at);select id into v_workspace_id from public.workspaces where owner_id=v_user_id and kind='personal' order by created_at limit 1;if v_workspace_id is null then insert into public.workspaces(owner_id,name,kind) values(v_user_id,coalesce(nullif(trim(p_workspace_name),''),'Minhas finanças'),'personal') returning id into v_workspace_id;end if;insert into public.categories(workspace_id,owner_id,name,kind,color) values(v_workspace_id,v_user_id,'Salário','income','#087f5b'),(v_workspace_id,v_user_id,'Atendimentos','income','#0f766e'),(v_workspace_id,v_user_id,'Outras receitas','income','#2563eb'),(v_workspace_id,v_user_id,'Moradia','expense','#c2410c'),(v_workspace_id,v_user_id,'Alimentação','expense','#b45309'),(v_workspace_id,v_user_id,'Transporte','expense','#7c3aed'),(v_workspace_id,v_user_id,'Saúde','expense','#be123c'),(v_workspace_id,v_user_id,'Lazer','expense','#0369a1'),(v_workspace_id,v_user_id,'Contas','expense','#475569'),(v_workspace_id,v_user_id,'Outras despesas','expense','#64748b') on conflict do nothing;return v_workspace_id;end;$$;
revoke all on function public.bootstrap_personal_workspace(text,text,text) from public,anon;grant execute on function public.bootstrap_personal_workspace(text,text,text) to authenticated;
